// auto-iteration.ts 中添加 Dashboard 通知
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices: any;

  constructor(config: Partial<IterationConfig> = {}) {
    // ... 现有代码
  }

  /**
   * 通知 Dashboard
   */
  private async notifyDashboard(event: string, data: any) {
    try {
      const { realtimeService, iterationService } = getServices();

      switch(event) {
        case 'iteration.started':
          await iterationService.create({
            iterationNumber: this.iterationCount,
            status: 'running',
            requirement: data.task
          });
          await realtimeService.broadcastIterationStatusChange({
            iterationNumber: this.iterationCount,
            status: 'running',
            timestamp: new Date()
          });
          break;

        case 'iteration.progress':
          await realtimeService.broadcastIterationProgress({
            iterationNumber: this.iterationCount,
            phase: data.phase,
            progress: data.progress,
            message: data.message
          });
          break;

        case 'agent.status_changed':
          await realtimeService.broadcastAgentStatusChange({
            agentName: data.agent,
            status: data.status,
            currentTask: data.task
          });
          break;

        case 'iteration.completed':
          await iterationService.update(this.iterationCount, {
            status: 'completed',
            completedAt: new Date()
          });
          await realtimeService.broadcastIterationStatusChange({
            iterationNumber: this.iterationCount,
            status: 'completed',
            timestamp: new Date()
          });
          break;
      }
    } catch (error) {
      console.error('Failed to notify dashboard:', error);
    }
  }

  async start(): Promise<void> {
    if (this.isRunning) return;
    this.isRunning = true;

    while (this.isRunning) {
      this.iterationCount++;

      // 通知迭代开始
      await this.notifyDashboard('iteration.started', { 
        iterationNumber: this.iterationCount 
      });

      try {
        await this.runIteration();

        // 通知迭代完成
        await this.notifyDashboard('iteration.completed', {
          iterationNumber: this.iterationCount
        });
      } catch (error) {
        await this.notifyDashboard('iteration.failed', { error });
      }

      await this.sleep(this.config.intervalMs);
    }
  }

  private async runIteration(): Promise<void> {
    // Phase 1: 产品经理
    await this.notifyDashboard('iteration.progress', {
      phase: 'product_manager',
      progress: 10,
      message: '产品经理分析中...'
    });

    const analysisResult = await this.productManager.executeAndCollect(/* ... */);

    // Phase 2: 架构师
    await this.notifyDashboard('iteration.progress', {
      phase: 'architect',
      progress: 30,
      message: '架构设计中...'
    });

    const designResult = await this.agents.architect.executeAndCollect(/* ... */);

    // ... 其他阶段
  }
}
