// services/realtime.service.ts

export class RealtimeService {
  private subscriptions = new Map<WebSocket, Set<string>>();
  private lastHeartbeats = new Map<WebSocket, number>();

  /**
   * 订阅频道
   */
  subscribe(client: WebSocket, channel: string): void {
    if (!this.subscriptions.has(client)) {
      this.subscriptions.set(client, new Set());
    }
    this.subscriptions.get(client)!.add(channel);
    this.lastHeartbeats.set(client, Date.now());

    this.logger.info({
      client: client.readyState,
      channel,
      subscriptions: this.subscriptions.get(client)!.size
    }, 'Client subscribed');
  }

  /**
   * 取消订阅
   */
  unsubscribe(client: WebSocket, channel: string): void {
    if (this.subscriptions.has(client)) {
      this.subscriptions.get(client)!.delete(channel);
    }
  }

  /**
   * 广播到所有订阅者
   */
  broadcast(event: string, data: any): void {
    const message = JSON.stringify({ event, data });

    for (const [client, channels] of this.subscriptions) {
      if (client.readyState === WebSocket.OPEN) {
        try {
          client.send(message);
        } catch (error) {
          this.logger.error(error, 'Failed to send message');
          this.removeClient(client);
        }
      }
    }
  }

  /**
   * 心跳检测
   */
  startHeartbeat(): void {
    setInterval(() => {
      const now = Date.now();

      for (const [client, lastSeen] of this.lastHeartbeats) {
        // 超时断开
        if (now - lastSeen > this.heartbeatTimeout * 1000) {
          this.logger.warn('Client heartbeat timeout, closing connection');
          client.close();
          this.removeClient(client);
        }
      }

      // 发送心跳
      this.broadcast('ping', { timestamp: now });
    }, this.heartbeatInterval * 1000);
  }
}

// services/iteration.service.ts

export class IterationService {
  /**
   * 回滚到指定迭代
   */
  async rollback(iterationId: number): Promise<void> {
    const iteration = this.findById(iterationId);
    if (!iteration) {
      throw new Error('Iteration not found');
    }

    if (!iteration.gitCommit) {
      throw new Error('No git commit associated with this iteration');
    }

    // 执行 git 回滚
    try {
      execSync(`git reset --hard ${iteration.gitCommit}`, {
        cwd: this.projectPath
      });

      // 更新数据库状态
      this.db.prepare(`
        UPDATE iterations 
        SET status = 'rolled_back',
            rolled_back_at = ?
        WHERE id = ?
      `).run(new Date().toISOString(), iterationId);

      this.logger.info({ iterationId }, 'Rolled back to iteration');
    } catch (error) {
      this.logger.error(error, 'Failed to rollback');
      throw error;
    }
  }

  /**
   * 获取性能统计
   */
  getStats(): IterationStats {
    const iterations = this.db.prepare('SELECT * FROM iterations').all();

    const total = iterations.length;
    const successful = iterations.filter((i: any) => i.status === 'completed').length;
    const failed = iterations.filter((i: any) => i.status === 'failed').length;

    const avgDuration = total > 0
      ? iterations.reduce((sum: number, i: any) => sum + (i.duration || 0), 0) / total
      : 0;

    return {
      total,
      successful,
      failed,
      successRate: total > 0 ? (successful / total) * 100 : 0,
      avgDuration: Math.round(avgDuration)
    };
  }
}
