```typescript
// services/metrics.service.ts

export class MetricsCollector {
  private metrics: {
    agents: Array<{
      agent: string;
      duration: number;
      tokens: number;
      timestamp: Date;
    }>;
    apiCalls: Array<{
      endpoint: string;
      duration: number;
      success: boolean;
      timestamp: Date;
    }>;
    iterations: Array<{
      iterationNumber: number;
      duration: number;
      status: string;
      timestamp: Date;
    }>;
  };

  constructor() {
    this.metrics = {
      agents: [],
      apiCalls: [],
      iterations: []
    };
  }

  /**
   * 记录 Agent 执行
   */
  recordAgentExecution(
    agent: string,
    duration: number,
    tokens: number
  ): void {
    this.metrics.agents.push({
      agent,
      duration,
      tokens,
      timestamp: new Date()
    });
  }

  /**
   * 记录 API 调用
   */
  recordAPICall(
    endpoint: string,
    duration: number,
    success: boolean
  ): void {
    this.metrics.apiCalls.push({
      endpoint,
      duration,
      success,
      timestamp: new Date()
    });
  }

  /**
   * 获取性能报告
   */
  getPerformanceReport(): PerformanceReport {
    return {
      // Agent 性能
      avgExecutionTime: this.calculateAvg(this.metrics.agents, 'duration'),
      totalTokens: this.sum(this.metrics.agents, 'tokens'),

      // API 性能
      apiSuccessRate: this.calculateSuccessRate(this.metrics.apiCalls),
      avgApiResponseTime: this.calculateAvg(this.metrics.apiCalls, 'duration'),

      // 迭代性能
      avgIterationDuration: this.calculateAvg(this.metrics.iterations, 'duration'),
      iterationSuccessRate: this.calculateSuccessRate(this.metrics.iterations)
    };
  }

  private calculateAvg(arr: any[], key: string): number {
    if (arr.length === 0) return 0;
    return arr.reduce((sum, item) => sum + (item[key] || 0), 0) / arr.length;
  }

  private sum(arr: any[], key: string): number {
    return arr.reduce((sum, item) => sum + (item[key] || 0), 0);
  }

  private calculateSuccessRate(arr: any[]): number {
    if (arr.length === 0) return 0;
    const successful = arr.filter(item => item.success || item.status === 'completed').length;
    return (successful / arr.length) * 100;
  }
}
