      context: this.context,
      message,
      data,
      timestamp: new Date().toISOString()
    }));
  }

  error(message: string, error?: Error) {
    console.error(JSON.stringify({
      level: 'error',
      context: this.context,
      message,
      error: error?.stack,
      timestamp: new Date().toISOString()
    }));
  }
}
